const __pageData = JSON.parse('{"title":"并发范式：共享内存与消息传递","description":"从形式化定义到工程实现，系统探讨并发与并行的区分、共享内存与消息传递模型、软件事务内存、无锁数据结构及形式化验证方法，并映射到 JavaScript 的事件循环、Web Workers、SharedArrayBuffer、Promise 组合与 Node.js cluster，对比 Go、Erlang 与 Rust 的并发模型。","frontmatter":{"title":"并发范式：共享内存与消息传递","description":"从形式化定义到工程实现，系统探讨并发与并行的区分、共享内存与消息传递模型、软件事务内存、无锁数据结构及形式化验证方法，并映射到 JavaScript 的事件循环、Web Workers、SharedArrayBuffer、Promise 组合与 Node.js cluster，对比 Go、Erlang 与 Rust 的并发模型。","date":"2026-05-01T00:00:00.000Z","tags":["编程范式","并发编程","Concurrency","Parallelism","Web Workers","SharedArrayBuffer","Actor","CSP","Promise","Node.js"],"category":"theoretical-foundations"},"headers":[],"relativePath":"programming-paradigms/08-concurrent-paradigm.md","filePath":"programming-paradigms/08-concurrent-paradigm.md","lastUpdated":1777809704000}');
